import { useMemo } from 'react';

import { legendItem, legendNameWrapper } from './ChartLegendItem.sty.js';
import { Tooltip } from '../../../../../../../overlays/tooltip/Tooltip.js';
import { useLegend } from '../../hooks/useLegend.js';
import { useLegendItemActions } from '../../hooks/useLegendItemActions.js';
import { useLegendItemInteractions } from '../../hooks/useLegendItemInteractions.js';
import { useLegendItemState } from '../../hooks/useLegendItemState.js';
import { LEGEND_MESSAGES } from '../../messages.js';
import { LegendItem } from '../../types/legend.js';
import { ChartLegendIcon } from '../ChartLegendIcon/ChartLegendIcon.js';
import { ChartLegendItemLabel } from '../ChartLegendItemLabel/ChartLegendItemLabel.js';
import { ChartLegendSeriesActions } from '../ChartLegendSeriesActions/ChartLegendSeriesActions.js';

interface ChartLegendItemProps {
  item: LegendItem;
  active?: HTMLElement;
  numberOfItems: number;
}

export const ChartLegendItem = (props: ChartLegendItemProps) => {
  const { item, numberOfItems } = props;

  const {
    hiddenItems,
    onLegendIconClick,
    onItemHover,
    onLegendNameClick,
    interactionsDisabled,
    onSeriesAction: actions,
  } = useLegend();

  const {
    refIconButton,
    refNameButton,
    open,
    updateOpenState,
    updateHoveredState,
    updateVisible,
    visible,
    isLastItem,
    shouldShowActionsButton,
    isIconHovered,
  } = useLegendItemState(
    item,
    interactionsDisabled,
    hiddenItems,
    numberOfItems,
  );

  const {
    handleLabelMouseEnter,
    handleIconMouseEnter,
    handleMouseLeave,
    onNameButtonClick,
    onNameButtonKeyDown,
    onIconButtonClick,
  } = useLegendItemInteractions(
    item,
    {
      onItemHover,
      onLegendIconClick,
      onLegendNameClick,
      updateHoveredState,
      updateVisible,
      visible,
    },
    interactionsDisabled,
  );

  const onLegendItemAction = () => {
    onItemHover(undefined);
    updateHoveredState(false);
  };

  const { intl, defaultActions } = useLegendItemActions(
    item,
    onLegendItemAction,
  );

  const iconButtonClickHandler = !isLastItem ? onIconButtonClick : undefined;
  const disabled = interactionsDisabled || isLastItem;
  const memoizedActions = useMemo(() => {
    if (open && actions) {
      return actions(item);
    }
  }, [open]);

  return (
    <div
      onMouseLeave={handleMouseLeave}
      data-testid="chart-legend-item"
      className={legendItem}
    >
      <Tooltip
        data-testid={
          disabled
            ? 'chart-legend-item-tooltip-disabled'
            : 'chart-legend-item-tooltip'
        }
        disabled={disabled}
        text={
          visible
            ? intl.formatMessage(LEGEND_MESSAGES.legendHideSeries)
            : intl.formatMessage(LEGEND_MESSAGES.legendShowSeries)
        }
        placement="left"
      >
        <ChartLegendIcon
          visible={visible}
          hover={isIconHovered}
          disabled={isLastItem}
          color={item.color.Default}
          icon={item.icon}
          buttonRef={refIconButton}
          onMouseEnter={handleIconMouseEnter}
          onButtonClick={iconButtonClickHandler}
        />
      </Tooltip>
      <div
        onFocus={handleLabelMouseEnter}
        data-testid="chart-legend-name-wrapper"
        className={legendNameWrapper}
      >
        <ChartLegendItemLabel
          item={item}
          visible={visible}
          buttonRef={refNameButton}
          onButtonClick={onNameButtonClick}
          onButtonKeydown={onNameButtonKeyDown}
          onMouseEnter={handleLabelMouseEnter}
          onMouseLeave={handleMouseLeave}
        />
        {actions && (
          <ChartLegendSeriesActions
            disabled={interactionsDisabled}
            visible={shouldShowActionsButton}
            onOpenChange={updateOpenState}
            isOpen={open}
            onFocus={handleLabelMouseEnter}
            onMouseEnter={handleLabelMouseEnter}
            onMouseLeave={handleMouseLeave}
            defaultActions={defaultActions}
            actions={memoizedActions}
            onBlur={handleMouseLeave}
          />
        )}
      </div>
    </div>
  );
};

ChartLegendItem['displayName'] = 'ChartLegendItem';
